# Core shapes module - defines abstract base classes, interfaces, and enums
enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3

interface IColorable:
    def get_color(self) -> Color: ...
    def set_color(self, value: Color) -> None: ...

@abstract
class Shape:
    _name: str

    def __init__(self, name: str):
        self._name = name

    def get_name(self) -> str:
        return self._name

    @abstract
    def area(self) -> float: ...

    @virtual
    def describe(self) -> str:
        return f"Shape: {self._name}"

