# Geometric shape implementations - demonstrates inheritance and interface implementation
from shapes import Color, IColorable, Shape

class Rectangle(Shape, IColorable):
    width: float
    height: float
    _color: Color

    def __init__(self, name: str, width: float, height: float):
        super().__init__(name)
        self.width = width
        self.height = height
        self._color = Color.RED

    @override
    def area(self) -> float:
        return self.width * self.height

    def get_color(self) -> Color:
        return self._color

    def set_color(self, value: Color) -> None:
        self._color = value

    @override
    def describe(self) -> str:
        return f"Rectangle {self._name} ({self.width}x{self.height})"

class Circle(Shape):
    radius: float

    def __init__(self, name: str, radius: float):
        super().__init__(name)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def describe(self) -> str:
        return f"Circle {self._name} (r={self.radius})"
